// ========== API 调用方法 ==========

export const LotteryAdvancedAPI = {
  // ===== 策略配置 =====

  /**
   * 获取策略配置列表
   * @param {Object} [params={}] - 查询参数
   * @returns {Promise<Object>} 策略列表
   */
  async getStrategyList(params = {}) {
    const url = LOTTERY_ADVANCED_ENDPOINTS.STRATEGY_LIST + buildQueryString(params)
    return await request({ url, method: 'GET' })
  },

  /**
   * 获取策略详情
   * @param {number} id - 策略 ID
   * @returns {Promise<Object>} 策略详情
   */
  async getStrategyDetail(id) {
    const url = buildURL(LOTTERY_ADVANCED_ENDPOINTS.STRATEGY_DETAIL, { id })
    return await request({ url, method: 'GET' })
  },

  /**
   * 创建策略配置
   * @param {Object} data - 策略数据
   * @returns {Promise<Object>} 创建结果
   */
  async createStrategy(data) {
    return await request({ url: LOTTERY_ADVANCED_ENDPOINTS.STRATEGY_CREATE, method: 'POST', data })
  },

  /**
   * 更新策略配置
   * @param {number} id - 策略 ID
   * @param {Object} data - 更新数据
   * @returns {Promise<Object>} 更新结果
   */
  async updateStrategy(id, data) {
    const url = buildURL(LOTTERY_ADVANCED_ENDPOINTS.STRATEGY_UPDATE, { id })
    return await request({ url, method: 'PUT', data })
  },

  /**
   * 删除策略配置
   * @param {number} id - 策略 ID
   * @returns {Promise<Object>} 删除结果
   */
  async deleteStrategy(id) {
    const url = buildURL(LOTTERY_ADVANCED_ENDPOINTS.STRATEGY_DELETE, { id })
    return await request({ url, method: 'DELETE' })
  },

  // ===== 成长等级公示分级概率（B 线） =====

  /**
   * 获取成长等级阶梯定义（公示）
   * @param {Object} [params={}] - 查询参数（如 include_inactive）
   * @returns {Promise<Object>} { levels: [{level_key, level_name, min_history_points, earn_multiplier, sort_order, status, description}] }
   */
  async getGrowthLevels(params = {}) {
    const url = LOTTERY_ADVANCED_ENDPOINTS.GROWTH_LEVELS_LIST + buildQueryString(params)
    return await request({ url, method: 'GET' })
  },

  /**
   * 更新成长等级定义（阈值/展示名/发放倍数/状态，拍板①②⑧）
   * @param {number} user_growth_level_id - 成长等级主键
   * @param {Object} data - 可更新字段 { level_name?, min_history_points?, earn_multiplier?, sort_order?, status?, description? }
   * @returns {Promise<Object>} 更新后的等级定义
   */
  async updateGrowthLevel(user_growth_level_id, data) {
    const url = buildURL(LOTTERY_ADVANCED_ENDPOINTS.GROWTH_LEVEL_UPDATE, { user_growth_level_id })
    return await request({ url, method: 'PUT', data })
  },

  /**
   * 获取某活动各成长等级中奖率倍数
   * @param {number} lottery_campaign_id - 活动 ID
   * @returns {Promise<Object>} { lottery_campaign_id, items: [{level_key, level_name, min_history_points, multiplier}] }
   */
  async getLevelProbability(lottery_campaign_id) {
    const url = buildURL(LOTTERY_ADVANCED_ENDPOINTS.LEVEL_PROBABILITY_GET, { lottery_campaign_id })
    return await request({ url, method: 'GET' })
  },

  /**
   * 批量配置某活动各成长等级中奖率倍数
   * @param {number} lottery_campaign_id - 活动 ID
   * @param {Array<Object>} items - [{level_key, multiplier}]
   * @returns {Promise<Object>} 配置结果
   */
  async updateLevelProbability(lottery_campaign_id, items) {
    const url = buildURL(LOTTERY_ADVANCED_ENDPOINTS.LEVEL_PROBABILITY_UPDATE, {
      lottery_campaign_id
    })
    return await request({ url, method: 'PUT', data: { items } })
  }
}

export default LotteryAdvancedAPI
